async function execute(api, params) {
    const chart = await api.webFetch("https://onlyhit.us/charts/kpop-thisweek/");

    const topSong = await api.queryLLM(
        "Extract the #1 song from this K-pop chart. Return a JSON object with 'trackName' (song title) and 'artist' (artist name) fields. If there are multiple artists, put them in a single string separated by commas.",
        { input: chart.text, parseJson: true, model: "claude-haiku-4-5-20251001" },
    );

    if (!topSong.data || !topSong.data.trackName) {
        return { success: false, error: "Could not extract the #1 K-pop song from the chart" };
    }

    const result = await api.callAction("player", "playTrack", {
        trackName: topSong.data.trackName,
        artists: [topSong.data.artist],
    });

    return { success: true, message: result.text };
}
